    const dirs = [[0, 1], [1, 0]];

    // Initialize a 2D array to store the minimum cost to reach each cell
    // We use a 2D array of size (m x n) to store the minimum cost
    const dp: number[][] = Array(m).fill(null).map(() => Array(n).fill(Infinity));

    // Starting cell (0, 0)
    dp[0][0] = (0 + 1) * (0 + 1); // Entry cost

    // Priority queue for Dijkstra's algorithm
    // Each element is [totalCost, row, col, time]
    // We use a min-heap to always process the cell with the smallest cost
    const pq = new PriorityQueue<[number, number, number]>();
    pq.enqueue([dp[0][0], 0, 0]);

    while (!pq.isEmpty()) {
        const [cost, row, col] = pq.dequeue();

        // If we have reached the destination, return the cost
        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        // Check if current cost is higher than the known minimum cost
        if (cost > dp[row][col]) {
            continue;
        }

        // Determine the current time step
        const time = (row * n + col) + 1; // Time starts from 1

        // If it's an odd time step (1st, 3rd, 5th, ...), we can move right or down
        if (time % 2 === 1) {
            for (const [dr, dc] of dirs) {
                const newRow = row + dr;
                const newCol = col + dc;

                // Check if the new cell is within bounds
                if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                    const newCost = cost + (newRow + 1) * (newCol + 1);

                    if (newCost < dp[newRow][newCol]) {
                        dp[newRow][newCol] = newCost;
                        pq.enqueue([newCost, newRow, newCol]);
                    }
                }
            }
        } 
        // If it's an even time step (2nd, 4th, 6th, ...), we must wait
        else {
            // Wait cost is added to the current cost
            const newCost = cost + waitCost[row][col];

            if (newCost < dp[row][col]) {
                dp[row][col] = newCost;
                pq.enqueue([newCost, row, col]);
            }
        }
    }

    // If we can't reach the destination, return -1 (should not happen in valid inputs)
    return -1;
}

